// src/pages/ResultsPage.js
import React, { useEffect, useRef, useState } from "react";
import { saveSession } from "../utils/firebase";
import "./ResultsPage.css";

const FILLER_WORDS = ["uh", "um", "like", "you know", "so", "basically",
  "actually", "literally", "right", "okay", "well", "hmm", "er", "ah"];

// Highlights filler words in red, other words normal
function HighlightedTranscript({ transcript, fillerCounts }) {
  if (!transcript) return <span>No transcript available.</span>;

  const fillerSet = new Set(Object.keys(fillerCounts).map(w => w.toLowerCase()));

  // Tokenize keeping spaces and punctuation
  const tokens = transcript.split(/(\s+)/);

  return (
    <span>
      {tokens.map((token, i) => {
        const clean = token.toLowerCase().replace(/[^a-z\s]/g, "").trim();
        const isFillerExact = fillerSet.has(clean);
        // check multi-word fillers like "you know"
        const isMultiWord = [...fillerSet].some(f => f.includes(" ") && transcript.toLowerCase().includes(f));

        if (isFillerExact) {
          return (
            <mark key={i} className="highlight-filler" title="Filler word">
              {token}
            </mark>
          );
        }
        return <span key={i}>{token}</span>;
      })}
    </span>
  );
}

// Renders feedback with bold section headers
function FormattedFeedback({ feedback }) {
  if (!feedback) return null;
  const lines = feedback.split("\n").filter(Boolean);
  return (
    <div className="feedback-sections">
      {lines.map((line, i) => {
        const isBoldHeader = line.startsWith("**") && line.endsWith("**");
        if (isBoldHeader) {
          const text = line.replace(/\*\*/g, "");
          return <p key={i} className="feedback-section-header">{text}</p>;
        }
        // inline bold like **word**
        const parts = line.split(/(\*\*[^*]+\*\*)/g);
        return (
          <p key={i} className="feedback-para">
            {parts.map((part, j) =>
              part.startsWith("**") && part.endsWith("**")
                ? <strong key={j}>{part.replace(/\*\*/g, "")}</strong>
                : part
            )}
          </p>
        );
      })}
    </div>
  );
}

function ScoreRing({ score }) {
  const r = 54;
  const circ = 2 * Math.PI * r;
  const offset = circ - (score / 100) * circ;
  const color = score >= 80 ? "#4ecca3" : score >= 60 ? "#ffd166" : "#fc6c8f";
  const label = score >= 80 ? "Excellent" : score >= 60 ? "Good" : "Needs Work";
  return (
    <div className="score-ring-wrap">
      <div className="score-ring">
        <svg viewBox="0 0 120 120" width="120" height="120">
          <circle className="score-ring-bg" cx="60" cy="60" r={r} />
          <circle className="score-ring-fill" cx="60" cy="60" r={r}
            strokeDasharray={circ} strokeDashoffset={offset} stroke={color} />
        </svg>
        <div className="score-ring-text">
          <span className="score-num" style={{ color }}>{score}</span>
          <span className="score-label">/ 100</span>
        </div>
      </div>
      <span className="tag" style={{ background: `${color}22`, color }}>{label}</span>
    </div>
  );
}

function MetricCard({ label, value, unit, note, color = "#7c6cfc" }) {
  return (
    <div className="metric-card card">
      <span className="metric-value" style={{ color }}>{value}</span>
      <span className="metric-unit">{unit}</span>
      <span className="metric-label">{label}</span>
      {note && <span className="metric-note">{note}</span>}
    </div>
  );
}

// Pronunciation tips based on common Filipino English patterns
function PronunciationCoach({ transcript }) {
  if (!transcript) return null;

  const text = transcript.toLowerCase();
  const tips = [];

  // Common Filipino pronunciation patterns to watch for
  const checks = [
    {
      pattern: /\bthe\b/g,
      count: (text.match(/\bthe\b/g) || []).length,
      tip: 'Practice the "th" sound in "the" — place your tongue lightly between your teeth. Many speakers replace it with "d" (saying "de") which affects clarity.',
      icon: "👅",
    },
    {
      pattern: /\bthink|three|through|thought|thank/g,
      words: (text.match(/\bthink|three|through|thought|thank/g) || []),
      tip: 'Words like "think", "three", "through" use the "th" sound — not "t". Try saying it slowly: put tongue between teeth and blow air.',
      icon: "💨",
    },
    {
      pattern: /\bvery|have|live|love|voice/g,
      words: (text.match(/\bvery|have|live|love|voice/g) || []),
      tip: 'The letter "v" should be pronounced with your top teeth touching your lower lip. It\'s different from "b" — practice "very" vs "berry".',
      icon: "🦷",
    },
    {
      pattern: /\band\b|\band\b/g,
      count: (text.match(/\band\b/g) || []).length,
      tip: 'The word "and" is often rushed. In formal speaking like thesis defense or interviews, give it its full sound — not just "en" or "an".',
      icon: "🔗",
    },
    {
      pattern: /\bcan\b|\bcannot\b/g,
      words: (text.match(/\bcan\b|\bcannot\b/g) || []),
      tip: '"Can" and "cannot" sound very similar when spoken fast. Stress "cannot" clearly — listeners need to hear the negative.',
      icon: "🔊",
    },
  ];

  // Add word ending tip always — very common issue
  tips.push({
    icon: "✂️",
    label: "Word endings",
    tip: 'Dropping word endings is common — saying "speakin" instead of "speaking", "runnin" instead of "running". Slow down slightly at the end of words to make them complete.',
  });

  // Add checks that apply
  checks.forEach(c => {
    const found = c.words ? c.words.length > 0 : c.count > 1;
    if (found) {
      tips.push({ icon: c.icon, label: null, tip: c.tip });
    }
  });

  // Always add stress tip
  tips.push({
    icon: "📣",
    label: "Stress & emphasis",
    tip: 'Use word stress to highlight key ideas. In a sentence like "This STUDY shows...", stressing "study" tells the listener what matters. Monotone delivery makes content hard to follow.',
  });

  // Limit to 4 tips max to avoid overwhelming
  const displayTips = tips.slice(0, 4);

  return (
    <div className="card pronunciation-card">
      <div className="feedback-header">
        <span className="feedback-icon">🗣️</span>
        <div>
          <h3>Pronunciation Coach</h3>
          <p className="feedback-sub">Tips to make your speech clearer and more confident</p>
        </div>
      </div>
      <div className="pronunciation-tips">
        {displayTips.map((t, i) => (
          <div key={i} className="pronunciation-tip">
            <span className="tip-icon">{t.icon}</span>
            <p className="tip-text">{t.tip}</p>
          </div>
        ))}
      </div>
      <div className="pronunciation-drill">
        <span className="drill-label">🎯 Quick drill</span>
        <p>Read this sentence slowly and clearly: <em>"The three thoughtful students thoroughly reviewed their thesis through the night."</em> — it targets "th", word endings, and pacing all at once.</p>
      </div>
    </div>
  );
}

export default function ResultsPage({ navigate, results }) {
  const { transcript, metrics, feedback, scenario } = results || {};
  const saved = useRef(false);
  const [showTranscript, setShowTranscript] = useState(false);

  useEffect(() => {
    if (!saved.current && metrics) {
      saved.current = true;
      saveSession({ scenario, transcript, metrics, feedback, date: new Date().toISOString() });
    }
  }, []);

  if (!results) return <div className="results-page center"><p>No results found.</p></div>;

  const wpmColor = metrics.wpm >= 120 && metrics.wpm <= 160 ? "#4ecca3" : metrics.wpm > 160 ? "#fc6c8f" : "#ffd166";
  const fillerColor = metrics.totalFillers === 0 ? "#4ecca3" : metrics.totalFillers <= 5 ? "#ffd166" : "#fc6c8f";
  const scoreColor = metrics.score >= 80 ? "#4ecca3" : metrics.score >= 60 ? "#ffd166" : "#fc6c8f";

  return (
    <div className="results-page">
      <nav className="navbar">
        <span className="navbar-logo" onClick={() => navigate("landing")}>CLARIO</span>
        <div className="navbar-links">
          <button className="btn btn-ghost" onClick={() => navigate("dashboard")}>📊 Dashboard</button>
          <button className="btn btn-primary" onClick={() => navigate("practice")}>🎙️ Practice Again</button>
        </div>
      </nav>

      <div className="results-inner">
        {/* Header */}
        <div className="results-header">
          <span className="tag tag-purple">{scenario}</span>
          <h1>Your Results</h1>
          <p className="results-date">{new Date().toLocaleDateString("en-PH", { month: "long", day: "numeric", year: "numeric" })}</p>
        </div>

        {/* Score + Metrics */}
        <div className="score-row">
          <ScoreRing score={metrics.score} />
          <div className="metrics-grid">
            <MetricCard label="Speech Rate"   value={metrics.wpm}          unit="WPM"     color={wpmColor}    note={metrics.wpm > 160 ? "Try slowing down" : metrics.wpm < 100 ? "Try speeding up" : "Great pace!"} />
            <MetricCard label="Total Words"   value={metrics.totalWords}   unit="words"   color="#a99dff" />
            <MetricCard label="Filler Words"  value={metrics.totalFillers} unit="fillers" color={fillerColor} note={metrics.totalFillers > 5 ? "Try pausing instead" : metrics.totalFillers === 0 ? "Perfect!" : "Good job!"} />
            <MetricCard label="Overall Score" value={metrics.score}        unit="/ 100"   color={scoreColor} />
          </div>
        </div>

        {/* Filler word breakdown */}
        {Object.keys(metrics.fillerCounts).length > 0 && (
          <div className="card filler-section">
            <h3 className="section-h3">🔍 Filler Word Breakdown</h3>
            <div className="filler-chips">
              {Object.entries(metrics.fillerCounts).sort((a, b) => b[1] - a[1]).map(([word, count]) => (
                <div key={word} className="filler-chip">
                  <span className="filler-word">"{word}"</span>
                  <span className="filler-count">{count}×</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* AI Coaching Feedback */}
        <div className="card feedback-card">
          <div className="feedback-header">
            <span className="feedback-icon">🤖</span>
            <div>
              <h3>AI Coaching Feedback</h3>
              <p className="feedback-sub">Personalized insights powered by Claude</p>
            </div>
          </div>
          <div className="feedback-body">
            <FormattedFeedback feedback={feedback} />
          </div>
        </div>

        {/* Pronunciation Coach */}
        <PronunciationCoach transcript={transcript} />

        {/* Transcript with highlights */}
        <div className="card transcript-section">
          <button className="transcript-toggle" onClick={() => setShowTranscript(!showTranscript)}>
            <div className="transcript-toggle-left">
              <span>📝 View Transcript</span>
              {Object.keys(metrics.fillerCounts).length > 0 && (
                <span className="transcript-legend">
                  <mark className="legend-mark">highlighted</mark> = filler words
                </span>
              )}
            </div>
            <span>{showTranscript ? "▲" : "▼"}</span>
          </button>
          {showTranscript && (
            <div className="transcript-body">
              <HighlightedTranscript
                transcript={transcript}
                fillerCounts={metrics.fillerCounts}
              />
            </div>
          )}
        </div>

        {/* Actions */}
        <div className="results-actions">
          <button className="btn btn-primary" onClick={() => navigate("practice")}>
            🎙️ Practice Again
          </button>
          <button className="btn btn-outline" onClick={() => navigate("dashboard")}>
            📈 View Progress
          </button>
        </div>
      </div>
    </div>
  );
}
